def topological_sort(graph):
    visited = set()
    stack = []

    def dfs(node):
        visited.add(node)
        for neighbor in graph[node]:
            if neighbor not in visited:
                dfs(neighbor)
        stack.append(node)

    for node in [0, 1, 2, 3]:
        if node not in visited:
            dfs(node)

    return stack[::-1]

