def is_bipartite(graph):
    color = {}

    def dfs(node, c):
        color[node] = c
        for neighbor in graph[node]:
            if neighbor not in color:
                if not dfs(neighbor, 1 - c):
                    return False
            elif color[neighbor] == c:
                return False
        return True

    for node in graph:
        if node not in color:
            if not dfs(node, 0):
                return False
    return True

