def kosaraju(graph, n):
    def dfs1(node, visited, stack):
        visited[node] = True
        for neighbor in graph[node]:
            if not visited[neighbor]:
                dfs1(neighbor, visited, stack)
        stack.append(node)

    def dfs2(node, visited, component):
        visited[node] = True
        component.append(node)
        for neighbor in transpose[node]:
            if not visited[neighbor]:
                dfs2(neighbor, visited, component)

    # Create transpose graph
    transpose = {i: [] for i in range(n)}
    for u in graph:
        for v in graph[u]:
            transpose[v].append(u)

    # First DFS
    visited = [False] * n
    stack = []
    for i in range(n):
        if not visited[i]:
            dfs1(i, visited, stack)

    # Second DFS
    visited = [False] * n
    scc_count = 0
    while stack:
        node = stack.pop()
        if not visited[node]:
            component = []
            dfs2(node, visited, component)
