def is_valid_coloring(graph, coloring):
    for node in graph:
        for neighbor in graph[node]:
            if coloring[node] == coloring[neighbor]:
                return False
    return True

def can_color_with_k_colors(graph, k):
    n = len(graph)
    coloring = [0] * n

    def backtrack(node):
        if node == n:
            return is_valid_coloring(graph, coloring)

        for color in range(k):
            coloring[node] = color
            valid = True
            for neighbor in graph[node]:
                if neighbor < node and coloring[neighbor] == color:
                    valid = False
                    break
            if valid and backtrack(node + 1):
                return True

        return False

    return backtrack(0)

