def graph_density(graph, directed=False):
    n = len(graph)
    if n <= 1:
        return 0

    edge_count = 0
    for node in graph:
        edge_count += len(graph[node])

    if not directed:
        edge_count //= 2

    max_edges = n * (n - 1)
    if not directed:
        max_edges //= 2

    return edge_count / max_edges

