def max_matching_bipartite(left_nodes, right_nodes, edges):
    graph = {node: [] for node in left_nodes}
    for u, v in edges:
        graph[u].append(v)

    match_right = {}
    match_left = {}

    def dfs(u, visited):
        for v in graph[u]:
            if v not in visited:
                visited.add(v)
                if v not in match_right or dfs(match_right[v], visited):
                    match_right[v] = u
                    match_left[u] = v
                    return True
        return False

    matching = 0
    for u in left_nodes:
        visited = set()
        if dfs(u, visited):
            matching += 1

    return matching

