def greedy_coloring(graph):
    n = len(graph)
    colors = [-1] * n
    colors[0] = 0

    for node in range(1, n):
        available_colors = set(range(n))

        for neighbor in graph[node]:
            if colors[neighbor] != -1:
                available_colors.discard(colors[neighbor])

        colors[node] = min(available_colors)

    return max(colors) + 1

