from itertools import permutations

def count_automorphisms(graph, n):
    def is_automorphism(perm):
        for node in graph:
            mapped_neighbors = set(perm[neighbor] for neighbor in graph[node])
            actual_neighbors = set(graph[perm[node]])
            if mapped_neighbors != actual_neighbors:
                return False
        return True

    count = 0
    for perm in permutations(range(n)):
        if is_automorphism(perm):
            count += 1

    return count

