def vertex_cover_greedy(graph, n):
    edges = set()
    for u in graph:
        for v in graph[u]:
            if u < v:
                edges.add((u, v))

    cover = set()
    edges_copy = edges.copy()

    while edges_copy:
        # Find vertex with maximum degree
        degree_count = {i: 0 for i in range(n)}
        for u, v in edges_copy:
            degree_count[u] += 1
            degree_count[v] += 1

        max_vertex = max(degree_count, key=degree_count.get)
        if degree_count[max_vertex] == 0:
            break

        cover.add(max_vertex)

        # Remove edges incident to max_vertex
        edges_to_remove = []
        for u, v in edges_copy:
            if u == max_vertex or v == max_vertex:
                edges_to_remove.append((u, v))

        for edge in edges_to_remove:
            edges_copy.remove(edge)

    return len(cover)

