def max_independent_set_greedy(graph, n):
    remaining = set(range(n))
    independent_set = set()

    while remaining:
        # Find vertex with minimum degree among remaining vertices
        min_degree = float('inf')
        min_vertex = -1

        for vertex in remaining:
            degree = len([neighbor for neighbor in graph[vertex] if neighbor in remaining])
            if degree < min_degree:
                min_degree = degree
                min_vertex = vertex

        # Add min_vertex to independent set
        independent_set.add(min_vertex)

        # Remove min_vertex and its neighbors from remaining
        to_remove = {min_vertex}
