def domination_number_greedy(graph, n):
    uncovered = set(range(n))
    dominating_set = set()

    while uncovered:
        # Find vertex that covers the most uncovered vertices
        best_vertex = -1
        max_coverage = -1

        for vertex in range(n):
            if vertex in dominating_set:
                continue

            coverage = 0
            if vertex in uncovered:
                coverage += 1

            for neighbor in graph[vertex]:
                if neighbor in uncovered:
                    coverage += 1

            if coverage > max_coverage:
                max_coverage = coverage
                best_vertex = vertex

        dominating_set.add(best_vertex)

        # Mark as covered
        if best_vertex in uncovered:
            uncovered.remove(best_vertex)

        for neighbor in graph[best_vertex]:
            if neighbor in uncovered:
                uncovered.remove(neighbor)

    return len(dominating_set)

