        for i in range(len(vertices)):
            for j in range(i + 1, len(vertices)):
                if vertices[j] not in graph[vertices[i]]:
                    return False
        return True

    def extend_clique(current_clique, candidates):
        if not candidates:
            if len(current_clique) > 0:
                cliques.append(current_clique.copy())
            return

        for vertex in candidates.copy():
            # Add vertex to current clique
            new_clique = current_clique + [vertex]

            # Find new candidates (neighbors of all vertices in new_clique)
            new_candidates = set(graph[vertex])
            for v in current_clique:
                new_candidates &= set(graph[v])

            # Remove already processed vertices
            new_candidates = [v for v in new_candidates if v > vertex]

            extend_clique(new_clique, new_candidates)
            candidates.remove(vertex)

    cliques = []
    for start in range(n):
        candidates = [v for v in graph[start] if v > start]
        extend_clique([start], candidates)

    return len([clique for clique in cliques if len(clique) >= 3])

