def greedy_bandwidth(graph, n):
    # Start with vertex of minimum degree
    degrees = [(len(graph[i]), i) for i in range(n)]
    degrees.sort()

    ordering = [degrees[0][1]]
    remaining = set(range(n)) - {degrees[0][1]}

    while remaining:
        # Find vertex in remaining that has most connections to already ordered vertices
        best_vertex = -1
        max_connections = -1

        for vertex in remaining:
            connections = len([neighbor for neighbor in graph[vertex] if neighbor in ordering])
            if connections > max_connections:
                max_connections = connections
                best_vertex = vertex

        if max_connections == 0:
            best_vertex = min(remaining)

        ordering.append(best_vertex)
        remaining.remove(best_vertex)

    return calculate_bandwidth(graph, ordering)

