def graph_edit_distance(graph1, graph2, n1, n2):
    # Simple approximation based on degree sequences
    def get_degree_multiset(graph, n):
        degrees = []
        for i in range(n):
            if i in graph:
                degrees.append(len(graph[i]))
            else:
                degrees.append(0)
        return sorted(degrees)

    degrees1 = get_degree_multiset(graph1, n1)
    degrees2 = get_degree_multiset(graph2, n2)

    # Pad shorter sequence with zeros
    max_len = max(len(degrees1), len(degrees2))
    degrees1.extend([0] * (max_len - len(degrees1)))
    degrees2.extend([0] * (max_len - len(degrees2)))

    # Calculate L1 distance between degree sequences
    distance = sum(abs(d1 - d2) for d1, d2 in zip(degrees1, degrees2))

    return distance // 2  # Each edge contributes to two vertices

