def page_rank(graph, n, damping=0.85, iterations=10):
    # Initialize page rank values
    pr = [1.0 / n] * n

    for _ in range(iterations):
        new_pr = [0.0] * n

        for i in range(n):
            # Base probability
            new_pr[i] = (1 - damping) / n

            # Add contributions from incoming links
            for j in range(n):
                if i in graph.get(j, []):
                    out_degree = len(graph.get(j, []))
                    if out_degree > 0:
                        new_pr[i] += damping * pr[j] / out_degree

        pr = new_pr

    # Return index of highest page rank
    return pr.index(max(pr))

