def girvan_newman_step(graph, n):
    # Calculate edge betweenness for each edge
    edge_betweenness = {}

    def shortest_paths_from(start):
        distances = [-1] * n
        distances[start] = 0
        queue = [start]
        paths = {start: 1}

        for node in queue:
            for neighbor in graph.get(node, []):
                if distances[neighbor] == -1:
                    distances[neighbor] = distances[node] + 1
                    paths[neighbor] = paths[node]
                    queue.append(neighbor)
                elif distances[neighbor] == distances[node] + 1:
                    paths[neighbor] += paths[node]

        return distances, paths

    # Calculate betweenness for all edges
    for start in range(n):
        distances, paths = shortest_paths_from(start)
        for node in range(n):
            if distances[node] > 0:
                for neighbor in graph.get(node, []):
                    if distances[neighbor] == distances[node] + 1:
                        edge = tuple(sorted([node, neighbor]))
                        if edge not in edge_betweenness:
                            edge_betweenness[edge] = 0
                        edge_betweenness[edge] += paths[node] / paths[neighbor]

    if not edge_betweenness:
        return 0

    # Return the maximum betweenness value
    return max(edge_betweenness.values())

