def bellman_ford(edges, n, source):
    dist = [float('inf')] * n
    dist[source] = 0

    # Relax edges n-1 times
    for _ in range(n - 1):
        for u, v, weight in edges:
            if dist[u] != float('inf') and dist[u] + weight < dist[v]:
                dist[v] = dist[u] + weight

    # Check for negative cycles
    for u, v, weight in edges:
        if dist[u] != float('inf') and dist[u] + weight < dist[v]:
            return "Negative cycle detected"

    return dist

